/* eslint-disable no-console */
/**
 * Writes a compact i18n audit summary to GitHub Actions job summary (if available).
 *
 * Usage (CI):
 *   node scripts/i18n-audit-ci-summary.mjs
 *
 * Expects:
 * - i18n-audit.json (generated by scripts/i18n-audit.mjs)
 * - scripts/i18n-audit-baseline.json
 */

import fs from "node:fs";
import path from "node:path";

const REPO_ROOT = process.cwd();
const AUDIT_JSON = path.join(REPO_ROOT, "i18n-audit.json");
const BASELINE_JSON = path.join(REPO_ROOT, "scripts", "i18n-audit-baseline.json");

function readJson(p) {
  return JSON.parse(fs.readFileSync(p, "utf8"));
}

function fmtDelta(cur, base) {
  if (typeof cur !== "number" || typeof base !== "number") return "";
  const d = cur - base;
  if (d === 0) return "";
  return d > 0 ? ` (+${d})` : ` (${d})`;
}

function md(s) {
  return String(s).replace(/\|/g, "\\|");
}

function main() {
  if (!fs.existsSync(AUDIT_JSON)) {
    console.error(`Missing ${AUDIT_JSON}. Run scripts/i18n-audit.mjs first.`);
    process.exit(2);
  }
  if (!fs.existsSync(BASELINE_JSON)) {
    console.error(`Missing ${BASELINE_JSON}. Create with npm run i18n:baseline (dedicated PR).`);
    process.exit(2);
  }

  const audit = readJson(AUDIT_JSON);
  const baseline = readJson(BASELINE_JSON);

  const m = audit.metrics;
  const b = baseline.metrics ?? {};

  const lines = [];
  lines.push("## i18n audit");
  lines.push("");
  lines.push("| metric | current | baseline |");
  lines.push("|---|---:|---:|");
  lines.push(`| missing no | ${m.missing.no}${fmtDelta(m.missing.no, b.missing?.no)} | ${b.missing?.no ?? "?"} |`);
  lines.push(`| missing en | ${m.missing.en}${fmtDelta(m.missing.en, b.missing?.en)} | ${b.missing?.en ?? "?"} |`);
  lines.push(`| extra no | ${m.extra.no}${fmtDelta(m.extra.no, b.extra?.no)} | ${b.extra?.no ?? "?"} |`);
  lines.push(`| extra en | ${m.extra.en}${fmtDelta(m.extra.en, b.extra?.en)} | ${b.extra?.en ?? "?"} |`);
  lines.push(`| placeholders | ${m.placeholder}${fmtDelta(m.placeholder, b.placeholder)} | ${b.placeholder ?? "?"} |`);
  lines.push(`| interpolation mismatches | ${m.interpolationMismatch}${fmtDelta(m.interpolationMismatch, b.interpolationMismatch)} | ${b.interpolationMismatch ?? "?"} |`);
  lines.push(`| hardcoded actionable | ${m.hardcodedActionable.total}${fmtDelta(m.hardcodedActionable.total, b.hardcodedActionable?.total)} | ${b.hardcodedActionable?.total ?? "?"} |`);

  const curGroups = m.hardcodedActionable?.byGroup ?? {};
  const baseGroups = b.hardcodedActionable?.byGroup ?? {};
  for (const id of Object.keys(curGroups).sort((a, b) => a.localeCompare(b))) {
    lines.push(`| hardcoded actionable (${md(id)}) | ${curGroups[id]}${fmtDelta(curGroups[id], baseGroups?.[id])} | ${baseGroups?.[id] ?? "?"} |`);
  }

  lines.push(`| mojibake sv/no/en | ${m.mojibake.sv}/${m.mojibake.no}/${m.mojibake.en} | ${b.mojibake ? `${b.mojibake.sv}/${b.mojibake.no}/${b.mojibake.en}` : "?"} |`);
  lines.push("");

  const top = audit.topFiles?.hardcodedActionable ?? [];
  if (top.length) {
    lines.push("### Top files (hardcoded actionable)");
    lines.push("");
    lines.push("| file | count |");
    lines.push("|---|---:|");
    for (const t of top.slice(0, 10)) {
      lines.push(`| \`${md(t.file)}\` | ${t.count} |`);
    }
    lines.push("");
  }

  const summaryPath = process.env.GITHUB_STEP_SUMMARY;
  const out = lines.join("\n") + "\n";
  if (summaryPath) {
    fs.appendFileSync(summaryPath, out, "utf8");
  } else {
    console.log(out);
  }
}

main();
